const row = items[0]?.json ?? {};

const parseJson = (value) => {
  try {
    return JSON.parse(String(value ?? '{}'));
  } catch {
    return {};
  }
};

const toInt = (value) => Number.parseInt(String(value ?? 0), 10) || 0;
const toFloat = (value) => Number(value ?? 0) || 0;
const formatList = (value, fallback) => Array.isArray(value) && value.length > 0 ? value.join('; ') : fallback;
const formatMap = (value, fallback) => {
  if (!value || typeof value !== 'object') {
    return fallback;
  }
  const entries = Object.entries(value).filter(([, count]) => Number(count) > 0);
  return entries.length > 0 ? entries.map(([name, count]) => `${name}=${count}`).join(', ') : fallback;
};
const brDateTime = new Intl.DateTimeFormat('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  dateStyle: 'short',
  timeStyle: 'medium',
});
const brDate = new Intl.DateTimeFormat('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  dateStyle: 'short',
});
const formatCheckedAt = (value) => {
  if (!value) {
    return 'n/d';
  }
  const date = new Date(value);
  return Number.isNaN(date.getTime()) ? String(value) : brDateTime.format(date);
};
const formatReportDate = (value) => {
  if (!value) {
    return 'n/d';
  }
  const date = new Date(`${value}T00:00:00-03:00`);
  return Number.isNaN(date.getTime()) ? String(value) : brDate.format(date);
};

const logSummary = parseJson(row.stdout);
const day = row.local_day ?? logSummary.day_ref ?? 'n/d';
const checkedAt = logSummary.app_ping_checked_at ?? null;
const checkedAtLabel = formatCheckedAt(checkedAt);
const reportDateLabel = formatReportDate(day);
const reportWindowStart = row.report_window_start_local ?? logSummary.report_window_start_local ?? '00:00:00';
const reportWindowEnd = row.report_window_end_local ?? logSummary.report_window_end_local ?? '23:59:59';
const reportWindowTimezone = row.report_window_timezone ?? logSummary.report_window_timezone ?? 'America/Sao_Paulo';
const reportWindowTimezoneLabel = reportWindowTimezone === 'America/Sao_Paulo'
  ? 'horario de Sao Paulo'
  : String(reportWindowTimezone).replace(/_/g, ' ');
const reportWindowLabel = `${reportWindowStart} a ${reportWindowEnd} (${reportWindowTimezoneLabel})`;
const checkedDateKey = checkedAt && !Number.isNaN(new Date(checkedAt).getTime())
  ? new Intl.DateTimeFormat('en-CA', { timeZone: 'America/Sao_Paulo' }).format(new Date(checkedAt))
  : null;
const reportDateKey = /^\d{4}-\d{2}-\d{2}$/.test(String(day ?? '')) ? String(day) : null;
const appStatus = String(logSummary.app_ping_status ?? 'OFF').toUpperCase() === 'ON' ? 'ON' : 'OFF';
const appPingStatusCode = logSummary.app_ping_http_status ?? 'n/d';
const appPingLatency = logSummary.app_ping_latency_ms == null ? 'n/d' : `${Number(logSummary.app_ping_latency_ms).toFixed(2)} ms`;
const appPingError = logSummary.app_ping_error ? ` | detalhe: ${logSummary.app_ping_error}` : '';
const success = toInt(row.success_count);
const failures = toInt(row.failure_count);
const total = toInt(row.total_events);
const rate = toFloat(row.failure_rate_pct).toFixed(2);
const critical = toInt(row.critical_count);
const webhookFailed = toInt(row.webhook_failed_count);
const peakHour = row.peak_hour ?? 'n/d';
const amount = row.success_amount ?? '0';
const emailDone = toInt(row.email_done_count);
const emailFailed = toInt(row.email_failed_count);
const emailPending = toInt(row.email_pending_backlog);
const totalUsers = toInt(row.total_users);
const totalChurches = toInt(row.total_churches);
const totalEventsCatalog = toInt(row.total_events_catalog);
const totalMembers = toInt(row.total_members);
const totalCollaborators = toInt(row.total_collaborators);
const totalAssemblies = toInt(row.total_assemblies);
const totalDocuments = toInt(row.total_documents);
const totalFinancialTransactions = toInt(row.total_financial_transactions);
const newUsers = toInt(row.new_users);
const newChurches = toInt(row.new_churches);
const newEvents = toInt(row.new_events);
const newMembers = toInt(row.new_members);
const newCollaborators = toInt(row.new_collaborators);
const newAssemblies = toInt(row.new_assemblies);
const newDocuments = toInt(row.new_documents);
const newFinancialTransactions = toInt(row.new_financial_transactions);
const dailyReconciliations = toInt(row.daily_reconciliations);

const httpTotal = toInt(logSummary.http_requests_total);
const http2xx = toInt(logSummary.http_2xx);
const http3xx = toInt(logSummary.http_3xx);
const http4xx = toInt(logSummary.http_4xx);
const http5xx = toInt(logSummary.http_5xx);
const topPaths = formatList(logSummary.top_paths, 'n/d');
const errorPaths = formatList(logSummary.error_paths, 'nenhuma');
const errorServices = formatMap(logSummary.errors_by_service, 'nenhum');
const warnServices = formatMap(logSummary.warns_by_service, 'nenhum');
const totalErrorSignals = Object.values(logSummary.errors_by_service ?? {}).reduce((sum, value) => sum + toInt(value), 0);
const totalWarnSignals = Object.values(logSummary.warns_by_service ?? {}).reduce((sum, value) => sum + toInt(value), 0);
const logSummaryError = logSummary._meta_error ? `- observacao: resumo de logs incompleto (${logSummary._meta_error})` : null;

const referenceLines = checkedDateKey && reportDateKey && checkedDateKey === reportDateKey
  ? [`Data de checagem e data-base do relatorio: ${checkedAtLabel} | janela considerada: ${reportWindowLabel}`]
  : [
      `Data de checagem: ${checkedAtLabel}`,
      `Data-base do relatorio: ${reportDateLabel} | janela considerada: ${reportWindowLabel}`,
    ];

const messageLines = [
  `Resumo FeConect (${day})`,
  '',
  ...referenceLines,
  `Status inicial da aplicacao: ${appStatus}`,
  `- /ping: HTTP ${appPingStatusCode} | latencia ${appPingLatency}${appPingError}`,
  '',
  'Aplicacao:',
  `- ${httpTotal} requisicoes HTTP no dia`,
  `- status HTTP: ${http2xx} 2xx | ${http3xx} 3xx | ${http4xx} 4xx | ${http5xx} 5xx`,
  `- rotas mais acessadas: ${topPaths}`,
  `- rotas com 4xx/5xx: ${errorPaths}`,
  `- sinais em logs: ${totalErrorSignals} erros relevantes | ${totalWarnSignals} warnings`,
  `- servicos com erro: ${errorServices}`,
  `- servicos com warning: ${warnServices}`,
  '',
  'Financeiro e integracoes:',
  `- ${success} pagamentos confirmados/recebidos de ${total}`,
  `- ${failures} pagamentos nao ok | taxa de falha ${rate}%`,
  `- valor confirmado: R$ ${amount}`,
  `- ${webhookFailed} webhooks com falha | ${critical} criticos (3+ tentativas)`,
  `- emails: ${emailDone} processados | ${emailFailed} com falha | ${emailPending} pendentes`,
  `- lancamentos financeiros: ${totalFinancialTransactions} na base | ${newFinancialTransactions} criados no dia`,
  `- conciliacoes bancarias realizadas no dia: ${dailyReconciliations}`,
  `- pico operacional as ${peakHour}h`,
  '',
  'Contexto da base:',
  `- base atual: ${totalUsers} usuarios | ${totalChurches} igrejas | ${totalEventsCatalog} eventos | ${totalMembers} membros | ${totalCollaborators} colaboradores | ${totalAssemblies} assembleias | ${totalDocuments} documentos | ${totalFinancialTransactions} lancamentos`,
  `- criados no dia: ${newUsers} usuarios | ${newChurches} igrejas | ${newEvents} eventos | ${newMembers} membros | ${newCollaborators} colaboradores | ${newAssemblies} assembleias | ${newDocuments} documentos | ${newFinancialTransactions} lancamentos`,
];

if (logSummaryError) {
  messageLines.push('', logSummaryError);
}

return [{
  json: {
    message: messageLines.join('\n'),
    summary: row,
    logSummary,
  },
}];
